1	type Item = { type: string };
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: "quote"; items: Item[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const firstInsuranceSurcharge = (premium: number): number => premium / 10;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const BLOCK_PREMIUM = 60;
26	
27	const isBlock = (items: Item[]): boolean =>
28	  items.length === 3 && items.every((item) => item.type === items[0].type);
29	
30	const basePremiumFor = (items: Item[]): number =>
31	  isBlock(items)
32	    ? BLOCK_PREMIUM
33	    : items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
34	
35	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
36	
37	const quotePremium = (items: Item[]): number => {
38	  const basePremium = basePremiumFor(items);
39	  return roundUpToWholeGold(
40	    basePremium + firstInsuranceSurcharge(basePremium) + PROCESSING_FEE,
41	  );
42	};
43	
44	export const runScenario = (scenario: Scenario): ScenarioResult => ({
45	  results: [{ premium: quotePremium(scenario.steps[0].items) }],
46	});
